#include <stdio.h>
#include <math.h>
#include <stdlib.h>

#define N 400020

int main() {
    int ar[N];
    for (int i = 0; i < N; i++) {
        int x = 0;
        int b = 5;
        while (b <= i) {
            x += i / b;
            b *= 5;
        }
        ar[i] = x;
    }

    int n;
    scanf("%d", &n);

    int sol[N];
    int count = 0;
    for (int i = 0; i < N; i++) {
        if (ar[i] == n) {
            sol[count++] = i;
        }
    }

    printf("%d\n", count);
    for (int i = 0; i < count; i++) {
        printf("%d ", sol[i]);
    }
    printf("\n");

    return 0;
}
